from beeai_framework import AgentState

def detect_memory_latency(agent_state: AgentState):
    memory_bytes = len(str(agent_state.memory).encode())
    tokens_estimate = memory_bytes / 4  # ~4 bytes per token
    projected_latency = tokens_estimate * 0.05  # 50ms per 1k tokens

    if projected_latency > 3000:
        print(f'⚠️ Memory-induced latency: {projected_latency:.0f}ms')
        return {'status': 'critical', 'tokens': tokens_estimate}
    return {'status': 'healthy'}

from beeai_framework.tools import GraniteTool

class GraniteLatencyDetector:
    def __init__(self):
        self.retry_counts = 0

    def on_tool_call(self, tool_call):
        if isinstance(tool_call.tool, GraniteTool):
            retries = tool_call.metadata.get('parse_retries', 0)
            self.retry_counts += retries
            if retries > 2:
                print(f'🚨 Granite parsing failed {retries} times')
                return {'issue': 'granite_format_inconsistency'}
        return {'status': 'ok'}

