from beeai_framework.models import GraniteModel

def speculative_granite_decode(prompt):
    model = GraniteModel()
    # Generate with speculative tokens for common formats
    speculative_formats = ['```json', '```yaml', '{', '[']
    for format_hint in speculative_formats:
        try:
            response = model.generate(prompt + format_hint, max_tokens=50)
            if model.validate_json(response):
                return response
        except:
            continue
    return model.generate(prompt)  # Fallback

agent.llm_provider = speculative_granite_decode
